args.sparql:
SELECT ?lakeLabel
WHERE {
  ?city wdt:P31 wd:Q515 ;
         wdt:P17 wd:Q16 .
  ?city p:P1082 ?populationStatement .
  ?populationStatement ps:P1082 ?population .
  ?populationStatement pq:P585 ?date .
  FILTER NOT EXISTS {
    ?city p:P1082 ?otherStatement .
    ?otherStatement pq:P585 ?otherDate .
    FILTER (?otherDate > ?date)
  }
  ?city wdt:P142 ?lake .
  OPTIONAL { ?lake rdfs:label ?lakeLabel . }
}
ORDER BY ?population
LIMIT 1

